output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?team1Label ?team2Label ?date WHERE {
  ?edition wdt:P1545 wd:Q265538 ; wdt:P585 ?date ; wdt:P1098 ?team1 , ?team2 .
  OPTIONAL {
    ?team1 rdfs:label ?team1Label
    FILTER(lang(?team1Label) = "en")
  }
  OPTIONAL {
    ?team2 rdfs:label ?team2Label
    FILTER(lang(?team2Label) = "en")
  }
}
ORDER BY DESC(?date)
LIMIT 1

